noncompliant:
public class Base
{
    public void SomeMethod(int count) { }
}
public class Derived : Base
{
    private void SomeMethod(int count) { } // Noncompliant: shadows base method with reduced visibility
}

compliant:
public class Base
{
    public void SomeMethod(int count) { }
}
public class Derived : Base
{
    public new void SomeMethod(int count) { } // OK: explicitly using 'new' keyword
}

public class Base
{
    protected virtual void Method() { }
}
public class Derived : Base
{
    protected override void Method() { } // OK: maintaining same visibility
}

public class Base
{
    protected virtual void Method() { }
}
public class Derived : Base
{
    public override void Method() { } // OK: increasing visibility
}
